    class_attributes,
    enrollment_requirements
) VALUES
    ('BUS-A 507', 'FINANCIAL REPORTING AND ANALYSIS II', '12866', 'Class Status', 'MW Monday, Wednesday 11:15 AM–12:45 PM', 'CG 1026', 'P.J. Hoffman', 19, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course examines the accounting for and presentation of information in financial statements from the perspective of financial statement users, focusing on specific topics such as cash, receivables, inventory, long-lived assets, financial instruments, investments, derivatives and hedging instruments, and liabilities.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-A 509', 'CAREER SUCCESS SKILLS', '5870', 'Class Status', 'F Friday 8:00 AM–12:00 PM', 'CG 1008', 'Holly McKenzie', 5, NULL, 'Lecture', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'There are two overriding objectives for this course: 1) to assist students in getting the "right" job upon graduation and 2) help the student to become more successful in their career. Item one has three elements: career awareness, self-awareness, and how to sell yourself. Item two requires learning how to "think like a manager" and to develop "soft skills" that are so important to career success.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-A 509', 'CAREER SUCCESS SKILLS', '15240', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 8:00 AM–5:00 PM', 'CG 3059', 'Christopher Cook', 18, NULL, 'Lecture', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'There are two overriding objectives for this course: 1) to assist students in getting the "right" job upon graduation and 2) help the student to become more successful in their career. Item one has three elements: career awareness, self-awareness, and how to sell yourself. Item two requires learning how to "think like a manager" and to develop "soft skills" that are so important to career success.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-A 509', 'CAREER SUCCESS SKILLS', '31493', 'Class Status', 'F Friday 8:00 AM–12:00 PM', 'HD TBA', 'David Greene', 4, NULL, 'Lecture', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'There are two overriding objectives for this course: 1) to assist students in getting the "right" job upon graduation and 2) help the student to become more successful in their career. Item one has three elements: career awareness, self-awareness, and how to sell yourself. Item two requires learning how to "think like a manager" and to develop "soft skills" that are so important to career success.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-A 509', 'CAREER SUCCESS SKILLS', '32779', 'Class Status', 'F Friday 8:00 AM–12:00 PM', 'CG 1040', 'David Greene', 5, NULL, 'Lecture', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'There are two overriding objectives for this course: 1) to assist students in getting the "right" job upon graduation and 2) help the student to become more successful in their career. Item one has three elements: career awareness, self-awareness, and how to sell yourself. Item two requires learning how to "think like a manager" and to develop "soft skills" that are so important to career success.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-A 509', 'CAREER SUCCESS SKILLS', '5271', 'Closed', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 8:00 AM–5:00 PM', 'CG 2069', 'Brett Levitt', 0, NULL, 'Lecture', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'There are two overriding objectives for this course: 1) to assist students in getting the "right" job upon graduation and 2) help the student to become more successful in their career. Item one has three elements: career awareness, self-awareness, and how to sell yourself. Item two requires learning how to "think like a manager" and to develop "soft skills" that are so important to career success.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-A 514', 'AUDITING THEORY AND PRACTICE', '5871', 'Class Status', 'MW Monday, Wednesday 11:00 AM–12:15 PM', 'CG 1008', 'Joe Schroeder', 1, NULL, 'Lecture', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], NULL, ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-A 514', 'AUDITING THEORY AND PRACTICE', '15032', 'Closed', 'MW Monday, Wednesday 11:00 AM–12:15 PM', 'CG 1008', 'Joe Schroeder', 0, NULL, 'Lecture', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], NULL, ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-A 514', 'AUDITING THEORY AND PRACTICE', '31495', 'Closed', 'MW Monday, Wednesday 9:30 AM–10:45 AM', 'CG 1040', 'Joe Schroeder', 0, NULL, 'Lecture', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], NULL, ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-A 527', 'TAXES AND FINANCIAL STATEMENTS', '10337', 'Closed', 'MW Monday, Wednesday 11:15 AM–12:45 PM', 'CG 2063', 'Bridget Stomberg', 0, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'Accounting for income taxes under Financial Accounting Standard #109. Topics include "book vs. tax" accounting differences, financial accounting rules for determining tax provisions, and disclosure requirements, as well as advanced issues such as business combinations, reorganizations and spin-offs, intraperiod and intercompany allocations, foreign and state implications, net operating loss carryforwards and the impact of tax planning.', ARRAY[]::TEXT[], NULL),
    ('BUS-A 527', 'TAXES AND FINANCIAL STATEMENTS', '10338', 'Closed', 'MW Monday, Wednesday 9:20 AM–10:50 AM', 'CG 1022', 'Bridget Stomberg', 0, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'Accounting for income taxes under Financial Accounting Standard #109. Topics include "book vs. tax" accounting differences, financial accounting rules for determining tax provisions, and disclosure requirements, as well as advanced issues such as business combinations, reorganizations and spin-offs, intraperiod and intercompany allocations, foreign and state implications, net operating loss carryforwards and the impact of tax planning.', ARRAY[]::TEXT[], NULL),
    ('BUS-A 531', 'TAXATION OF PARTNERSHIPS AND S CORPORATIONS', '10486', 'Class Status', 'Tu Tuesday 3:05 PM–6:05 PM', 'CG 2069', 'Sonja Rego', 12, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'Formation, operation, and liquidation of partnerships, limited liability companies (LLCs), and S corporations. Tax planning for typical scenarios.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-A 537', 'CORPORATE TAXATION I', '8331', 'Closed', 'MW Monday, Wednesday 9:20 AM–10:50 AM', 'CG 2069', 'Bridget Stomberg', 0, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'C corporation tax rules and tax planning applications for formations and operations.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-A 537', 'CORPORATE TAXATION I', '8332', 'Closed', 'MW Monday, Wednesday 11:15 AM–12:45 PM', 'CG 2069', 'Bridget Stomberg', 0, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'C corporation tax rules and tax planning applications for formations and operations.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-A 540', 'FINANCIAL ACCOUNTING CONCEPTS', '5872', 'Class Status', 'MW Monday, Wednesday 11:00 AM–12:15 PM', 'CG 1040', 'Donald Young', 6, NULL, 'Lecture', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'Provides students with a thorough understanding of corporate disclosure, especially in the areas of investments, liabilities, and shareholders equity. Considerable attention is devoted to the discussion of accounting standards and estimates. Students are exposed to competing theories and methods of accounting and different perspectives on recording certain types of transactions. Students learn to evaluate outcomes reported in financial statements from the perspectives of management, shareholders, auditors, and other interested parties in preparation for Financial Statement Analysis (A517). The course culminates in an integrated, multi disciplinary exercise involving and industry analysis.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-A 540', 'FINANCIAL ACCOUNTING CONCEPTS', '31496', 'Closed', 'MW Monday, Wednesday 9:30 AM–10:45 AM', 'CG 1008', 'Donald Young', 0, NULL, 'Lecture', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'Provides students with a thorough understanding of corporate disclosure, especially in the areas of investments, liabilities, and shareholders equity. Considerable attention is devoted to the discussion of accounting standards and estimates. Students are exposed to competing theories and methods of accounting and different perspectives on recording certain types of transactions. Students learn to evaluate outcomes reported in financial statements from the perspectives of management, shareholders, auditors, and other interested parties in preparation for Financial Statement Analysis (A517). The course culminates in an integrated, multi disciplinary exercise involving and industry analysis.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-A 547', 'STRATEGIC TAX PLANNING', '9643', 'Class Status', 'TuTh Tuesday, Thursday 1:10 PM–2:40 PM', 'CG 1026', 'Tom Lunsford', 12, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'Introduction to advanced tax planning opportunities from both a tax compliance and tax planning perspective that requires consideration of tax and nontax costs. Topics include entity choice, implicit tax costs, state and local taxation, nontaxable exchanges, compensation, international taxation, and mergers and acquisitions.', ARRAY[]::TEXT[], NULL),
    ('BUS-A 547', 'STRATEGIC TAX PLANNING', '9644', 'Class Status', 'TuTh Tuesday, Thursday 3:05 PM–4:35 PM', 'CG 1032', 'Tom Lunsford', 14, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'Introduction to advanced tax planning opportunities from both a tax compliance and tax planning perspective that requires consideration of tax and nontax costs. Topics include entity choice, implicit tax costs, state and local taxation, nontaxable exchanges, compensation, international taxation, and mergers and acquisitions.', ARRAY[]::TEXT[], NULL),
    ('BUS-A 562', 'ADVANCED FINANCIAL ACCOUNTING', '31519', 'Closed', 'MW Monday, Wednesday 1:10 PM–2:40 PM', 'CG 2061', 'P.J. Hoffman', 0, NULL, 'Lecture', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'Generally accepted accounting principles as applied to partnerships, business combinations, branches, foreign operations, and nonprofit organizations. Particular emphasis is given to consolidated financial statements.', ARRAY[]::TEXT[], NULL),
    ('BUS-A 562', 'ADVANCED FINANCIAL ACCOUNTING', '31520', 'Closed', 'MW Monday, Wednesday 3:05 PM–4:35 PM', 'CG 2061', 'P.J. Hoffman', 0, NULL, 'Lecture', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'Generally accepted accounting principles as applied to partnerships, business combinations, branches, foreign operations, and nonprofit organizations. Particular emphasis is given to consolidated financial statements.', ARRAY[]::TEXT[], NULL),
    ('BUS-A 568', 'APPLIED LEADERSHIP, POWER, PERSUASION AND PROFESSIONAL PRACTICE', '3173', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 8:00 AM–12:00 PM', 'CG 1026', 'Matthew Turk', 30, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course addresses how organizational success is facilitated by sound leadership with special emphasis on effectively exercise power and persuasion in business. The focus is upon understanding and using leadership principles in applied business situations. Material is drawn from a variety of sources ranging from classical and contemporary scholarly writings to case studies of recent business situations. Students learn to identify effective and ineffective leadership practices in various settings. This course forms a leadership development thread throughout.', ARRAY[]::TEXT[], NULL),
    ('BUS-A 568', 'APPLIED LEADERSHIP, POWER, PERSUASION AND PROFESSIONAL PRACTICE', '3265', 'Closed', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 1:00 PM–5:00 PM', 'CG 1026', 'Matthew Turk', 0, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course addresses how organizational success is facilitated by sound leadership with special emphasis on effectively exercise power and persuasion in business. The focus is upon understanding and using leadership principles in applied business situations. Material is drawn from a variety of sources ranging from classical and contemporary scholarly writings to case studies of recent business situations. Students learn to identify effective and ineffective leadership practices in various settings. This course forms a leadership development thread throughout.', ARRAY[]::TEXT[], NULL),
    ('BUS-A 569', 'FIELD CONSULTING', '1118', 'Class Status', NULL, 'MW Monday, Wednesday 8:00 AM–9:15 AM M Monday 6:00 PM–8:00 PM Regular Academic Session 8/25/2025–12/19/2025', 'HD TBA HD TBA', NULL, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'This course engages students in conducting field consulting for local businesses under the mentorship of a Learning in a Professional Environment (LIFE) professor. Teams of three to four students will host firms to identify real business problems related to accounting and information systems and formulate and implement solutions to those problems. Strong emphasis is placed upon critical and creative thinking in problem identification and solution templating. Teams develop a written executive summary and implementation plan and make presentations to the host firm''s management.', ARRAY[]::TEXT[], NULL),
    ('BUS-A 569', 'FIELD CONSULTING', '36217', 'Class Status', NULL, 'MW Monday, Wednesday 8:00 AM–9:15 AM M Monday 6:00 PM–8:00 PM Non Standard Session 8/25/2025–12/19/2025', 'HD TBA HD TBA', NULL, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'This course engages students in conducting field consulting for local businesses under the mentorship of a Learning in a Professional Environment (LIFE) professor. Teams of three to four students will host firms to identify real business problems related to accounting and information systems and formulate and implement solutions to those problems. Strong emphasis is placed upon critical and creative thinking in problem identification and solution templating. Teams develop a written executive summary and implementation plan and make presentations to the host firm''s management.', ARRAY[]::TEXT[], NULL),
    ('BUS-A 569', 'FIELD CONSULTING', '1117', 'Closed', NULL, 'MW Monday, Wednesday 8:00 AM–9:15 AM M Monday 6:00 PM–8:00 PM Non Standard Session 8/25/2025–12/19/2025', 'HD TBA HD TBA', NULL, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'This course engages students in conducting field consulting for local businesses under the mentorship of a Learning in a Professional Environment (LIFE) professor. Teams of three to four students will host firms to identify real business problems related to accounting and information systems and formulate and implement solutions to those problems. Strong emphasis is placed upon critical and creative thinking in problem identification and solution templating. Teams develop a written executive summary and implementation plan and make presentations to the host firm''s management.', ARRAY[]::TEXT[], NULL),
    ('BUS-A 576', 'STRATEGIC COST MANAGEMENT', '11580', 'Class Status', 'TuTh Tuesday, Thursday 1:10 PM–2:40 PM', 'CG 2077', 'Jordan Bable', 2, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course provides students with the knowledge and analytical skills necessary to use accounting cost information as a basis for formulating and evaluating corporate strategies. A central theme of the course is that one of the primary functions of accounting information is to facilitate the development of corporate strategies. A superior accounting system provides an important tool for developing a sustainable competitive advantage by enabling a deep understanding of a company''s cost structure.', ARRAY[]::TEXT[], NULL),
    ('BUS-A 576', 'STRATEGIC COST MANAGEMENT', '11579', 'Closed', 'TuTh Tuesday, Thursday 11:15 AM–12:45 PM', 'CG 2077', 'Jordan Bable', 0, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course provides students with the knowledge and analytical skills necessary to use accounting cost information as a basis for formulating and evaluating corporate strategies. A central theme of the course is that one of the primary functions of accounting information is to facilitate the development of corporate strategies. A superior accounting system provides an important tool for developing a sustainable competitive advantage by enabling a deep understanding of a company''s cost structure.', ARRAY[]::TEXT[], NULL),
    ('BUS-A 591', 'FINANCIAL ACCOUNTING THEORY', '8807', 'Closed', 'TuTh Tuesday, Thursday 11:15 AM–12:45 PM', 'CG 1022', 'Angela Andrews', 0, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'The purpose of this course is best summarized by the question of "why" something is accounted for and not "how." The pursuit of an answer in this course is not narrowly focused on examining specific methods and practices, but also encompasses the question of why financial accounting exists at all.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-A 591', 'FINANCIAL ACCOUNTING THEORY', '10538', 'Closed', 'TuTh Tuesday, Thursday 9:20 AM–10:50 AM', 'CG 1022', 'Angela Andrews', 0, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'The purpose of this course is best summarized by the question of "why" something is accounted for and not "how." The pursuit of an answer in this course is not narrowly focused on examining specific methods and practices, but also encompasses the question of why financial accounting exists at all.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-A 602', 'EXPERIMENTAL RESEARCH IN ACCOUNTING', '5120', 'Class Status', 'W Wednesday 4:00 PM–7:00 PM', 'HH 5103', 'Donald Young', 6, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Introduction to experimental research in accounting.', ARRAY[]::TEXT[], NULL),
    ('BUS-A 603', 'SPECIAL RESEARCH TOPICS IN ACCOUNTING', '5312', 'Class Status', 'Th Thursday 9:00 AM–12:00 PM', 'HH 5103', 'Leslie Hodder', 3, NULL, 'Lecture', '1.5', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Doctoral level coverage of important research areas in accounting.', ARRAY[]::TEXT[], NULL),
    ('BUS-A 604', 'COLLOQUIUM IN ACCOUNTING RESEARCH', '12723', 'Class Status', 'F Friday 1:30 PM–3:00 PM', 'HH 5103', 'Donald Young', 4, NULL, 'Discussion', '1.5', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course develops students'' research skills through critical evaluation of current accounting research papers and participation in accounting department research workshops.', ARRAY[]::TEXT[], NULL),
    ('BUS-C 104', 'BUSINESS PRESENTATIONS', '5826', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'HH 3022', 'Trish Kerle''', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Students are introduced to oral communication in business contexts. The course focus is on theory-based skill development that will enable students to deliver audience-centered messages, work in teams, and analyze and develop oral arguments.', ARRAY['Class uses IU eTexts'], NULL),
