    ('BUS-D 271', 'GLOBAL BUSINESS ANALYSIS-INTERNATIONAL BUSINESS MANAGEMENT', '6102', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'BH 144', 'Zihao Jia', 0, NULL, 'Lecture', '1.5', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'D271 extends the knowledge gained in D270, Global Business Environment. This class concentrates directly on the management of multinational firms. Students are placed in the role of the decision-makers responsible for solving the myriad of practical problems resulting from a globalized and highly interconnected business environment.', ARRAY['Class uses IU eTexts'], NULL),
