    ('BUS-D 311', 'GLOBAL MANAGEMENT', '5853', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'HH 2000', 'Markus Vodosek', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course focuses on the management of multinational firms and the role of the global manager. Students are placed in the role of the decision-makers responsible for solving the myriad of practical problems resulting from a globalized and highly interconnected business environment.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-D 311', 'GLOBAL MANAGEMENT', '6670', 'Closed', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'HH 2000', 'Markus Vodosek', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course focuses on the management of multinational firms and the role of the global manager. Students are placed in the role of the decision-makers responsible for solving the myriad of practical problems resulting from a globalized and highly interconnected business environment.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-D 311', 'GLOBAL MANAGEMENT', '14808', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'HH 2000', 'Markus Vodosek', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course focuses on the management of multinational firms and the role of the global manager. Students are placed in the role of the decision-makers responsible for solving the myriad of practical problems resulting from a globalized and highly interconnected business environment.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-D 312', 'BUILDING MANAGERIAL CROSS CULTURAL COMPETENCIES', '7083', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'HH 2000', 'Erica Kovacs', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course focuses on the development of global leadership skills. It will help students to: understand the major trends affecting work; have a sense of cultural diversity and the interconnectedness of the world; foster effective communication; build teams quickly across multiple cultural environments; proactively manage their career progress.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-D 312', 'BUILDING MANAGERIAL CROSS CULTURAL COMPETENCIES', '14515', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'HH 3057', 'Erica Kovacs', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course focuses on the development of global leadership skills. It will help students to: understand the major trends affecting work; have a sense of cultural diversity and the interconnectedness of the world; foster effective communication; build teams quickly across multiple cultural environments; proactively manage their career progress.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-D 312', 'BUILDING MANAGERIAL CROSS CULTURAL COMPETENCIES', '29832', 'Closed', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'HH 2000', 'Erica Kovacs', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course focuses on the development of global leadership skills. It will help students to: understand the major trends affecting work; have a sense of cultural diversity and the interconnectedness of the world; foster effective communication; build teams quickly across multiple cultural environments; proactively manage their career progress.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-D 411', 'INTERNATIONAL COMPETITIVE STRATEGY', '8911', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'WH 109', 'Brian Hatton', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'This course is designed to provide an understanding of the interplay between the Multinational Corporation (MNC), the countries in which it does business, and the competitive environments in which it operates. The course takes a top management-level perspective on the design and implementation of MNC strategy.', ARRAY[]::TEXT[], NULL),
    ('BUS-D 411', 'INTERNATIONAL COMPETITIVE STRATEGY', '12685', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 005', 'Brian Hatton', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'This course is designed to provide an understanding of the interplay between the Multinational Corporation (MNC), the countries in which it does business, and the competitive environments in which it operates. The course takes a top management-level perspective on the design and implementation of MNC strategy.', ARRAY[]::TEXT[], NULL),
    ('BUS-D 411', 'INTERNATIONAL COMPETITIVE STRATEGY', '14809', 'Closed', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'HH 3055', 'Brian Hatton', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'This course is designed to provide an understanding of the interplay between the Multinational Corporation (MNC), the countries in which it does business, and the competitive environments in which it operates. The course takes a top management-level perspective on the design and implementation of MNC strategy.', ARRAY[]::TEXT[], NULL),
    ('BUS-D 503', 'NAVIGATING THE GLOBAL BUSINESS ENVIRONMENT', '1119', 'Closed', 'TuTh Tuesday, Thursday 11:15 AM–12:45 PM', 'CG 2061', 'Fred Schlegel', 0, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course familiarizes students with the global business environment. The focus is on introducing fundamental principles of how the world economy functions and analytic frameworks useful to managing across markets, cultures, and political systems. Special emphasis will be placed on the intellectual skills needed to develop a global mindset.', ARRAY[]::TEXT[], NULL),
    ('BUS-D 579', 'EXPERIMENTAL COURSE IN INTERNATIONAL BUSINESS', '33930', 'Class Status', 'MTuW Monday, Tuesday, Wednesday 8:00 AM–12:00 PM', 'CG 1022 CG 1022', 'Stephanie Wang', 4, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This seven week course focuses upon a new topic in International Business relevant to management decision making and appraisal of the external environment faced by organizations. Learning occurs through lecture, case discussion, problem solving, group projects, or completion of exercises that further the knowledge and skills of MBA students enrolled in the course.', ARRAY[]::TEXT[], NULL),
    ('BUS-F 100', 'INTRODUCTION TO FINANCIAL AND REAL ESTATE CAREERS', '10375', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'MN C210', 'Sridhar Arcot, Dubos Masson', 0, NULL, 'Lecture', '3', 'MCNUTT CENTRAL', ARRAY[]::TEXT[], 'Designed primarily for freshmen to learn about the full spectrum of financial and real estate careers. Covers financial intermediation, investment banking, mergers and acquisition, capital markets, real estate, investment management, corporate finance, commercial banking, treasury, equity research, investments, wealth management, international finance, hedge funds, fintech, private equity, and leveraged buy-outs.', ARRAY[]::TEXT[], NULL),
