    ('BUS-F 306', 'FINANCIAL MARKETS', '9059', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'WB WEB', 'Bob Musumeci', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course provides an overview of financial markets, including stock markets, bond markets, derivative markets, and active management markets. Specifically, it examines portfolio diversification, risk and return, mutual fund performance, market efficiency, bonds, options, and futures.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-F 306', 'FINANCIAL MARKETS', '34039', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'WB WEB', 'Rajiv Bhutani', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course provides an overview of financial markets, including stock markets, bond markets, derivative markets, and active management markets. Specifically, it examines portfolio diversification, risk and return, mutual fund performance, market efficiency, bonds, options, and futures.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-F 307', 'WORKING CAPITAL MANAGEMENT', '1134', 'Closed', 'M Monday 11:10 AM–12:25 PM', 'HH 1050 WB WEB', 'Jun Zhu', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL), WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course emphasizes the decisions financial managers face in determining short-term financial policy and ensuring its consistency with the operations of the company. Major topics include working capital elements and their relationships to company operations, financial analysis, cash forecasting, banking relations, cash flow systems and short-term investment and borrowing strategies.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-F 307', 'WORKING CAPITAL MANAGEMENT', '1135', 'Closed', 'M Monday 12:45 PM–2:00 PM', 'HH 1050 WB WEB', 'Jun Zhu', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL), WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course emphasizes the decisions financial managers face in determining short-term financial policy and ensuring its consistency with the operations of the company. Major topics include working capital elements and their relationships to company operations, financial analysis, cash forecasting, banking relations, cash flow systems and short-term investment and borrowing strategies.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-F 307', 'WORKING CAPITAL MANAGEMENT', '33881', 'Closed', 'W Wednesday 11:10 AM–12:25 PM', 'HH 1050 WB WEB', 'Jun Zhu', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL), WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course emphasizes the decisions financial managers face in determining short-term financial policy and ensuring its consistency with the operations of the company. Major topics include working capital elements and their relationships to company operations, financial analysis, cash forecasting, banking relations, cash flow systems and short-term investment and borrowing strategies.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-F 307', 'WORKING CAPITAL MANAGEMENT', '33882', 'Closed', 'W Wednesday 12:45 PM–2:00 PM', 'HH 1050 WB WEB', 'Jun Zhu', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL), WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course emphasizes the decisions financial managers face in determining short-term financial policy and ensuring its consistency with the operations of the company. Major topics include working capital elements and their relationships to company operations, financial analysis, cash forecasting, banking relations, cash flow systems and short-term investment and borrowing strategies.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-F 317', 'VENTURE CAPITAL AND ENTREPRENEURIAL FINANCE', '3762', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'HH 3000', 'David Haeberle', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Covers the private equity and debt markets providing finance to smaller entrepreneurial firms. Topics include: (1) the financial contracting associated with the provision of finance to small firms, (2) angel finance and the formal venture capital market, (3) commercial banks and l finance companies, and (4) start-ups and leveraged buyouts.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-F 317', 'VENTURE CAPITAL AND ENTREPRENEURIAL FINANCE', '4354', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'HH 2006', 'David Hirsch', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Covers the private equity and debt markets providing finance to smaller entrepreneurial firms. Topics include: (1) the financial contracting associated with the provision of finance to small firms, (2) angel finance and the formal venture capital market, (3) commercial banks and l finance companies, and (4) start-ups and leveraged buyouts.', ARRAY['Class uses IU eTexts'], NULL),
