    ('BUS-F 355', 'TOPICS IN FINANCE', '14776', 'Closed', 'Tu Tuesday 7:05 PM–8:20 PM', 'HH 1006', 'Gregory Renn', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Variable topic, variable credit course in Finance.', ARRAY[]::TEXT[], NULL),
    ('BUS-F 365', 'PERSONAL FINANCIAL PLANNING', '8637', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'MN C210', 'Gregory Renn', 0, NULL, 'Lecture', '3', 'MCNUTT CENTRAL', ARRAY[]::TEXT[], 'General course oriented towards theory and application of personal financial planning topics, with focus on the process of accumulating and protecting wealth, towards the goal of obtaining financial independence. Time value of money exercises and money management tools are utilized. Other topics examined include personal insurance issues, investments, in private and public securities, retirement planning, and estate planning.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-F 365', 'PERSONAL FINANCIAL PLANNING', '9461', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'MN C210', 'Gregory Renn', 0, NULL, 'Lecture', '3', 'MCNUTT CENTRAL', ARRAY[]::TEXT[], 'General course oriented towards theory and application of personal financial planning topics, with focus on the process of accumulating and protecting wealth, towards the goal of obtaining financial independence. Time value of money exercises and money management tools are utilized. Other topics examined include personal insurance issues, investments, in private and public securities, retirement planning, and estate planning.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-F 369', 'INSURANCE, RISK MANAGEMENT, AND RETIREMENT PLANNING', '9464', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'MN C210', 'Erik Benrud', 0, NULL, 'Lecture', '3', 'MCNUTT CENTRAL', ARRAY[]::TEXT[], 'Studies principles of insurance, risk management, and retirement planning as they apply to personal financial planning. Students will develop the knowledge and skills necessary to formualate financial plans to help individuals and families address needs in these areas.', ARRAY[]::TEXT[], NULL),
