    ('BUS-F 370', 'I-CORE - FINANCE COMPONENT', '11924', 'Closed', 'TuTh Tuesday, Thursday 3:45 PM–4:50 PM', 'HH 1055', 'Michael Oakes', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'The finance component provides a conceptual framework of a firm''s investment, financing, and dividend decisions; includes working capital management, capital budgeting, and capital structure strategies. Includes a cross-functional case done in teams.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-F 400', 'INVESTMENT BANKING WORKSHOP II', '10378', 'Closed', 'F Friday 12:45 PM–3:45 PM', 'HH 2006', 'David Haeberle', 0, NULL, 'Practicum', '1.5', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course continues the intense preparation for investment banking careers. The course further develops skills relevant to the industry, and provides experential activity. The course emphasizes professional development skills for success and students are expected to attend industry networking sessions.', ARRAY[]::TEXT[], NULL),
    ('BUS-F 402', 'CORPORATE FINANCIAL STRATEGY AND GOVERNANCE', '1141', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'HH 2006', 'Sena Durguner', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Advanced treatment of corporate financial management and governance topics. Covers lifecycle evolution of financial strategy and governance, private equity, capital budgeting and real options, capital structure, short/long-term financing, mergers, corporate governance, and risk management. Students undertake capstone projects on financial strategy and governance of real-world corporations and discuss with experts.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-F 402', 'CORPORATE FINANCIAL STRATEGY AND GOVERNANCE', '4482', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'HH 2006', 'Sena Durguner', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Advanced treatment of corporate financial management and governance topics. Covers lifecycle evolution of financial strategy and governance, private equity, capital budgeting and real options, capital structure, short/long-term financing, mergers, corporate governance, and risk management. Students undertake capstone projects on financial strategy and governance of real-world corporations and discuss with experts.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-F 411', 'CAPITAL MARKETS AND BANKING WORKSHOP II', '10379', 'Closed', 'Th Thursday 5:30 PM–6:45 PM', 'HH 4000', 'Sridhar Arcot', 0, NULL, 'Practicum', '1.5', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course continues the intense preparation for capital markets and commercial banking careers. The course further develops skills relevant to the industry, and provides experiential activity. The course emphasizes professional development skills for success and students are expected to attend industry networking sessions.', ARRAY[]::TEXT[], NULL),
    ('BUS-F 412', 'INVESTMENT MANAGEMENT WORKSHOP II', '35510', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'HH 3079', 'Eric Crigler', 0, NULL, 'Practicum', '1.5', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course continues the intense preparation for investment management careers. The course further develops skills relevant to the industry, and provides experential activity. The course emphasizes professional development skills for success and students are expected to attend industry networking sessions.', ARRAY[]::TEXT[], NULL),
    ('BUS-F 415', 'CORPORATE FINANCE/FP&A WORKSHOP CAPSTONE', '14843', 'Closed', 'W Wednesday 5:30 PM–8:00 PM', 'HH 2046', 'Majid Darvishan, Dubos Masson', 0, NULL, 'Practicum', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'The class will work with seniors in the workshop to bring together all related classes and to help them prepare for the FPAC certification exam. They will be introduced to the AFP certification exam prep site and helped to define a plan of study/preparation for the certification exam upon graduation.', ARRAY[]::TEXT[], NULL),
    ('BUS-F 419', 'BEHAVIORAL FINANCE', '7182', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'HH 2049', 'Charles Trzcinka', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Examines how human psychology influences the decisions of investors, markets, and managers. Learn how to avoid systematic investment errors, critically evaluate evidence of apparent anomalies in financial markets, and how to escape decision traps that afflict corporate managers.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-F 419', 'BEHAVIORAL FINANCE', '10163', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'HH 3079', 'Charles Trzcinka', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Examines how human psychology influences the decisions of investors, markets, and managers. Learn how to avoid systematic investment errors, critically evaluate evidence of apparent anomalies in financial markets, and how to escape decision traps that afflict corporate managers.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-F 420', 'EQUITY AND FIXED INCOME INVESTMENT', '1142', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'HH 1046', 'Michael Woeppel', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'A detailed examination of the management and valuation of equity and fixed income securities. The analysis of individual securities, the grouping of these securities into portfolios, and the use of derivative securities to modify the return/risk profiles of more traditional stock and bond portfolios will be discussed.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-F 420', 'EQUITY AND FIXED INCOME INVESTMENT', '7229', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'HH 1046', 'Michael Woeppel', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'A detailed examination of the management and valuation of equity and fixed income securities. The analysis of individual securities, the grouping of these securities into portfolios, and the use of derivative securities to modify the return/risk profiles of more traditional stock and bond portfolios will be discussed.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-F 420', 'EQUITY AND FIXED INCOME INVESTMENT', '10339', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'HH 1046', 'Michael Woeppel', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'A detailed examination of the management and valuation of equity and fixed income securities. The analysis of individual securities, the grouping of these securities into portfolios, and the use of derivative securities to modify the return/risk profiles of more traditional stock and bond portfolios will be discussed.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-F 421', 'DERIVATIVES SECURITIES/CORPORATE RISK MANAGEMENT', '9585', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'HH 3000', 'Zhenyu Wang', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course provides an in-depth examination of the institutional details of the derivative security markets and derivative security valuation. Additionally, speculative and risk management uses of derivatives are studied in detail.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-F 446', 'BANK AND FINANCIAL INTERMEDIATION', '6609', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'HH 1046', 'Kristoph Kleiner', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course covers the broad area of financial intermediation. The main topics studies are (i) the economic role of financial intermediaries--with an emphasis on commercial banks; (ii) the management of financial intermediaries; (iii) the regulation of commercial banks and other financial institutions.', ARRAY[]::TEXT[], NULL),
    ('BUS-F 455', 'TOPICS IN FINANCE', '14777', 'Closed', 'F Friday 12:30 PM–1:45 PM', 'HH 3000', 'Michael Goy', 0, NULL, 'Lecture', '1.5', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Variable topic, variable credit course in Finance.', ARRAY[]::TEXT[], NULL),
    ('BUS-F 507', 'SHORT-TERM FINANCIAL MANAGEMENT', '1144', 'Closed', 'MW Monday, Wednesday 9:20 AM–10:50 AM', 'CG 2061', 'Dubos Masson', 0, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'An exposure to the issues and problems addressed in the treasury function of a corporation. The focus is on the identification of the structure and the application of finance concepts to solve short-term, or operating, financial problems. Topics covered include a short-term evaluation model, cash management, short-term lending arrangements, daily cash forecasting, and credit policy. Market imperfections, institutional arrangements, and information problems that impede or assist solutions to treasury problems are addressed.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-F 508', 'VALUATION OF REAL OPTIONS', '5154', 'Class Status', 'TuTh Tuesday, Thursday 3:05 PM–4:35 PM', 'CG 1026', 'Erik Benrud', 4, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course is designed to develop more advanced capital budgeting skills so that the student may attack real-world corporate investment decisions in a sophisticated way.', ARRAY[]::TEXT[], NULL),
    ('BUS-F 511', 'MSF PRACTICUM I', '31545', 'Class Status', 'TuTh Tuesday, Thursday 9:20 AM–10:50 AM', 'CG 2063', 'Mark Wegener', 3, NULL, 'Practicum', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'MSF Practicum I is an intensive talent development program helping students become effective finance professionals. Students are immersed in financial decision-making through discussion and analysis of contemporary financial events and transactions by analyzing cases based on real-world financial transactions, listening to industry speakers, and understanding the financial landscape.', ARRAY[]::TEXT[], NULL),
    ('BUS-F 511', 'MSF PRACTICUM I', '31547', 'Class Status', 'TuTh Tuesday, Thursday 11:15 AM–12:45 PM', 'CG 1004', 'Mark Wegener', 2, NULL, 'Practicum', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'MSF Practicum I is an intensive talent development program helping students become effective finance professionals. Students are immersed in financial decision-making through discussion and analysis of contemporary financial events and transactions by analyzing cases based on real-world financial transactions, listening to industry speakers, and understanding the financial landscape.', ARRAY[]::TEXT[], NULL),
    ('BUS-F 516', 'CORPORATE FINANCE AND VALUATION', '33784', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 10:00 AM–11:30 AM', 'CG 1034 CG 1034 CG 1034', 'Steven Sibley', 21, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'Participants study basic principles of financial economics: the time value of money, law of one price, the impact of diversification and leverage on portfolio risk, the relationship between risk and expected return in securities markets, capital market efficiency and discounted cash flow as a foundation for stock prices.', ARRAY[]::TEXT[], NULL),
    ('BUS-F 517', 'VENTURE CAPITAL AND ENTREPRENEURIAL FINANCE', '1145', 'Class Status', 'MW Monday, Wednesday 3:05 PM–4:35 PM', 'CG 1026', 'Gerry Hays', 2, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'The analysis process for evaluating smaller, high potential investment opportunities where the investor plans to take an active role. Stresses the tools and concepts needed to evaluate the market, the technology, the management terms, and internal operations, resulting in a valuation and offer. Guest speakers and case studies are used.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-F 517', 'VENTURE CAPITAL AND ENTREPRENEURIAL FINANCE', '10162', 'Closed', 'MW Monday, Wednesday 1:10 PM–2:40 PM', 'CG 1026', 'Gerry Hays', 0, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'The analysis process for evaluating smaller, high potential investment opportunities where the investor plans to take an active role. Stresses the tools and concepts needed to evaluate the market, the technology, the management terms, and internal operations, resulting in a valuation and offer. Guest speakers and case studies are used.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-F 519', 'BEHAVIORAL FINANCE', '33887', 'Class Status', 'MW Monday, Wednesday 4:50 PM–6:20 PM', 'CG 2063', 'Sunil Teluja', 8, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'Behavioral Finance is the study of how "cognitive errors" influence the decisions of investors and managers and whether those errors exert a meaningful influence on prices in financial markets.', ARRAY[]::TEXT[], NULL),
    ('BUS-F 520', 'ASSET VALUATION AND STRATEGY', '1146', 'Closed', 'MW Monday, Wednesday 11:15 AM–12:45 PM', 'CG 2061', 'Seda Durguner', 0, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'An introduction to the basic theories for valuing equity, fixed income, and derivative securities. Covered in the equipty arena are the Capital Asset Pricing Model, Index Models, Arbitrage Pricing Theory, and empirical tests of these models. The price/yield relationship and term structure of interest rates are discussed in the fixed income portion of the course. Option and forward pricing models and basic risk management techniques also are presented.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-F 520', 'ASSET VALUATION AND STRATEGY', '5632', 'Closed', 'MW Monday, Wednesday 9:20 AM–10:50 AM', 'CG 1026', 'Seda Durguner', 0, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'An introduction to the basic theories for valuing equity, fixed income, and derivative securities. Covered in the equipty arena are the Capital Asset Pricing Model, Index Models, Arbitrage Pricing Theory, and empirical tests of these models. The price/yield relationship and term structure of interest rates are discussed in the fixed income portion of the course. Option and forward pricing models and basic risk management techniques also are presented.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-F 525', 'CORPORATE FINANCIAL RISK MANAGEMENT', '4293', 'Closed', 'TuTh Tuesday, Thursday 11:15 AM–12:45 PM', 'CG 2069', 'Majid Darvishan', 0, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'Explores the measurement and control of firm''s financial risk. Areas examined are exchange rate risk, interest rate risk, and commodity price risk. Risk management tools analyzed include forwards, futures, options, swaps, and newly-developed over-the-counter products. The role of corporate insurance is also discussed. The course will be useful to students interested in pursuing either corporate finance or investments careers.', ARRAY[]::TEXT[], NULL),
    ('BUS-F 525', 'CORPORATE FINANCIAL RISK MANAGEMENT', '10161', 'Closed', 'TuTh Tuesday, Thursday 9:20 AM–10:50 AM', 'CG 2063', 'Majid Darvishan', 0, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'Explores the measurement and control of firm''s financial risk. Areas examined are exchange rate risk, interest rate risk, and commodity price risk. Risk management tools analyzed include forwards, futures, options, swaps, and newly-developed over-the-counter products. The role of corporate insurance is also discussed. The course will be useful to students interested in pursuing either corporate finance or investments careers.', ARRAY[]::TEXT[], NULL),
    ('BUS-F 533', 'FINTECH FOR MANAGERS', '31510', 'Closed', 'TuTh Tuesday, Thursday 1:10 PM–2:40 PM', 'CG 2069', 'Troy Adair', 0, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This class introduces students to recent breakthroughs in fintech, while discussing the best practices for managing these financial firms. Through case studies, student develop a deeper understanding of the frictions that fintech aims to address and discover ways to overcome adoption barriers and quickly scale their business.', ARRAY[]::TEXT[], NULL),
    ('BUS-F 534', 'FINTECH APPS IN MACHINE LEARNING', '31509', 'Class Status', 'TuTh Tuesday, Thursday 3:05 PM–4:35 PM', 'CG 2069', 'Troy Adair', 15, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'The course begins by discussing the value of information in financial markets. Students then apply common machine learning techniques such as LASSO, logistic regressions, random forests, and principal components to predict a range of financial outcomes. The class concludes by overviewing the fintech landscape and the role of management.', ARRAY[]::TEXT[], NULL),
    ('BUS-F 540', 'THE FIRM IN THE CAPITAL MARKET', '9097', 'Class Status', 'TuTh Tuesday, Thursday 1:10 PM–2:40 PM', 'CG 2061', 'Majid Darvishan', 5, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'Examines the implications of capital market pricing for establishing corporate financial policy. The concepts of agency relationships, information asymmetry, and financial contracting provide a framework for analyzing financial decisions such as capital structure, dividends, share repurchase, managerial incentives, and the organizational form. Differences in institutional features are used to explain international patters in corporate financing.', ARRAY[]::TEXT[], NULL),
    ('BUS-F 540', 'THE FIRM IN THE CAPITAL MARKET', '11020', 'Class Status', 'TuTh Tuesday, Thursday 9:15 AM–10:45 AM', 'CG 1008', 'Majid Darvishan', 4, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'Examines the implications of capital market pricing for establishing corporate financial policy. The concepts of agency relationships, information asymmetry, and financial contracting provide a framework for analyzing financial decisions such as capital structure, dividends, share repurchase, managerial incentives, and the organizational form. Differences in institutional features are used to explain international patters in corporate financing.', ARRAY[]::TEXT[], NULL),
    ('BUS-F 540', 'THE FIRM IN THE CAPITAL MARKET', '30068', 'Class Status', 'TuTh Tuesday, Thursday 11:00 AM–12:30 PM', 'CG 1040', 'Majid Darvishan', 6, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'Examines the implications of capital market pricing for establishing corporate financial policy. The concepts of agency relationships, information asymmetry, and financial contracting provide a framework for analyzing financial decisions such as capital structure, dividends, share repurchase, managerial incentives, and the organizational form. Differences in institutional features are used to explain international patters in corporate financing.', ARRAY[]::TEXT[], NULL),
    ('BUS-F 541', 'SPREADSHEET MODELS IN FINANCE', '10842', 'Class Status', 'TuTh Tuesday, Thursday 9:20 AM–10:50 AM', 'CG 1008', 'Troy Adair', 6, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course helps students develop advanced spreadsheet skills for financial analysis. These skills include not only "number crunching" techniques, but also "best practices" in constructing models including using them as tools for communication of ideas and for influencing decisions. The examples will be built around the topic of financial planning.', ARRAY[]::TEXT[], NULL),
    ('BUS-F 541', 'SPREADSHEET MODELS IN FINANCE', '6505', 'Closed', 'TuTh Tuesday, Thursday 11:15 AM–12:45 PM', 'CG 1026', 'Troy Adair', 0, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course helps students develop advanced spreadsheet skills for financial analysis. These skills include not only "number crunching" techniques, but also "best practices" in constructing models including using them as tools for communication of ideas and for influencing decisions. The examples will be built around the topic of financial planning.', ARRAY[]::TEXT[], NULL),
    ('BUS-F 550', 'APPLIED PORTFOLIO SELECTION', '5911', 'Class Status', 'MW Monday, Wednesday 9:20 AM–10:50 AM', 'CG 1026', 'Eric Crigler', 4, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'A student group is selected to manage an existing portfolio of investments. Each student is responsible for analyzing an industry group and the associated firms. The major focus of the course is conducting a detailed security analysis and presenting the findings to the fund''s board of directors, which is composed of investment professionals. In essence, the students function as an independent investment management group for the portfolio. Admission to the class is selective based on the student''s academic and professional background and interest in the investment profession.', ARRAY[]::TEXT[], NULL),
    ('BUS-F 565', 'PERSONAL FINANCE', '11420', 'Class Status', 'MW Monday, Wednesday 3:05 PM–4:35 PM', 'CG 1040', 'Joseph Fitter', 2, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This class provides a hands-on opportunity to understand and apply the key concepts of financial planning as a precursor to getting your own financial house more in order. It teaches MBA/MS students about budgeting, tax planning, consumer credit, acquisition of big-ticket items, insurance, investment strategies, retirement planning, and estate planning.', ARRAY[]::TEXT[], NULL),
    ('BUS-F 600', 'ASSET PRICING THEORY', '9056', 'Class Status', 'TuTh Tuesday, Thursday 4:00 PM–5:30 PM', 'CG 1008', 'Zhenyu Wang', 15, NULL, 'Lecture', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'Focus is on developing the tools needed to fully appreciate models of financial asset valuation. These models are based on axioms of rational choice and economic first principles. Provides the foundation necessary to take other finance seminars.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-F 644', 'TOPICS IN FINANCE', '11332', 'Class Status', 'M Monday 12:00 PM–2:30 PM', 'HH 6103', 'Kristoph Kleiner', 13, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course covers various topics in finance. The class will discuss the academic literature in a given topic area.', ARRAY[]::TEXT[], NULL),
    ('BUS-G 202', 'BUSINESS, GOVERNMENT, AND SOCIETY', '3078', 'Closed', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'HH 2075', 'Philip Powell', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Successful business strategy must integrate the non-market forces that shape stakeholder expectations. Consumers, employees, and investors are increasingly motivated to make positive social-impact in their consumption activities, choice of employment, and portfolio allocations. Additionally, social activists and government policymakers are elevating the importance of having more credible sustainable business practices.', ARRAY[]::TEXT[], NULL),
    ('BUS-G 202', 'BUSINESS, GOVERNMENT, AND SOCIETY', '3172', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'HH 2075', 'Philip Powell', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Successful business strategy must integrate the non-market forces that shape stakeholder expectations. Consumers, employees, and investors are increasingly motivated to make positive social-impact in their consumption activities, choice of employment, and portfolio allocations. Additionally, social activists and government policymakers are elevating the importance of having more credible sustainable business practices.', ARRAY[]::TEXT[], NULL),
    ('BUS-G 202', 'BUSINESS, GOVERNMENT, AND SOCIETY', '4263', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'HH 2075', 'Ellie Mafi-Kreft', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Successful business strategy must integrate the non-market forces that shape stakeholder expectations. Consumers, employees, and investors are increasingly motivated to make positive social-impact in their consumption activities, choice of employment, and portfolio allocations. Additionally, social activists and government policymakers are elevating the importance of having more credible sustainable business practices.', ARRAY[]::TEXT[], NULL),
    ('BUS-G 202', 'BUSINESS, GOVERNMENT, AND SOCIETY', '5275', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'HH 2075', 'Steven Kreft', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Successful business strategy must integrate the non-market forces that shape stakeholder expectations. Consumers, employees, and investors are increasingly motivated to make positive social-impact in their consumption activities, choice of employment, and portfolio allocations. Additionally, social activists and government policymakers are elevating the importance of having more credible sustainable business practices.', ARRAY[]::TEXT[], NULL),
    ('BUS-G 202', 'BUSINESS, GOVERNMENT, AND SOCIETY', '6530', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'HH 2075', 'Ellie Mafi-Kreft', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Successful business strategy must integrate the non-market forces that shape stakeholder expectations. Consumers, employees, and investors are increasingly motivated to make positive social-impact in their consumption activities, choice of employment, and portfolio allocations. Additionally, social activists and government policymakers are elevating the importance of having more credible sustainable business practices.', ARRAY[]::TEXT[], NULL),
    ('BUS-G 202', 'BUSINESS, GOVERNMENT, AND SOCIETY', '8320', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'HH 2075', 'Steven Kreft', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Successful business strategy must integrate the non-market forces that shape stakeholder expectations. Consumers, employees, and investors are increasingly motivated to make positive social-impact in their consumption activities, choice of employment, and portfolio allocations. Additionally, social activists and government policymakers are elevating the importance of having more credible sustainable business practices.', ARRAY[]::TEXT[], NULL),
    ('BUS-G 300', 'INTRODUCTION TO MANAGERIAL ECONOMICS AND STRATEGY', '3718', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'WB WEB', 'Raphael Boleslavsky', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Microeconomic analysis and its applications to business decision making. Includes topics of demand and consumer behavior, production and costs, theory of firms, and public policy toward business. Focuses on the applied aspects of microeconomics.', ARRAY[]::TEXT[], NULL),
    ('BUS-G 300', 'INTRODUCTION TO MANAGERIAL ECONOMICS AND STRATEGY', '5444', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'WB WEB', 'Raphael Boleslavsky', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Microeconomic analysis and its applications to business decision making. Includes topics of demand and consumer behavior, production and costs, theory of firms, and public policy toward business. Focuses on the applied aspects of microeconomics.', ARRAY[]::TEXT[], NULL),
    ('BUS-G 300', 'INTRODUCTION TO MANAGERIAL ECONOMICS AND STRATEGY', '14179', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'WB WEB', 'Chang Liu', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Microeconomic analysis and its applications to business decision making. Includes topics of demand and consumer behavior, production and costs, theory of firms, and public policy toward business. Focuses on the applied aspects of microeconomics.', ARRAY[]::TEXT[], NULL),
    ('BUS-G 303', 'GAME THEORY FOR BUSINESS STRATEGY', '1147', 'Closed', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'CG 3044', 'Deepal Basak', 0, NULL, 'Lecture', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'Managerial decisions are not static and cannot be made in isolation. A manager must take into account and react to the "moves" of rival firms, government, and his or her subordinates and superiors within the company. Game theory is designed for the study of these types of interactions. The ultimate aim of the course is to strengthen your ability to think strategically in business situations, rather than to teach you facts or theories.', ARRAY[]::TEXT[], NULL),
    ('BUS-G 303', 'GAME THEORY FOR BUSINESS STRATEGY', '10403', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'CG 3044', 'Deepal Basak', 0, NULL, 'Lecture', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'Managerial decisions are not static and cannot be made in isolation. A manager must take into account and react to the "moves" of rival firms, government, and his or her subordinates and superiors within the company. Game theory is designed for the study of these types of interactions. The ultimate aim of the course is to strengthen your ability to think strategically in business situations, rather than to teach you facts or theories.', ARRAY[]::TEXT[], NULL),
    ('BUS-G 304', 'MANAGERIAL ECONOMICS', '3240', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'CG 3044', 'Marilyn Pease', 0, NULL, 'Lecture', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'Develop a framework based on economics to empower students to understand and effectively analyze a myriad of managerial problems. Sharpen the analytical tools required to solve these problems with mathematical rigor.', ARRAY[]::TEXT[], NULL),
    ('BUS-G 304', 'MANAGERIAL ECONOMICS', '4758', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'CG 3044', 'Marilyn Pease', 0, NULL, 'Lecture', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'Develop a framework based on economics to empower students to understand and effectively analyze a myriad of managerial problems. Sharpen the analytical tools required to solve these problems with mathematical rigor.', ARRAY[]::TEXT[], NULL),
    ('BUS-G 316', 'SUSTAINABLE ENTERPRISE', '6108', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'HH 3055', 'Steven Kreft', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'To investigate the challenges of implementing sustainability in a variety of contexts and under often divergent perspectives, giving the tools to identify and explain how sustainability creates new opportunities for, and constraints on, enterprise value creation.', ARRAY[]::TEXT[], NULL),
    ('BUS-G 345', 'MONEY, BANKING AND CAPITAL MARKETS', '3458', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'HH 1038', 'Francesco Marchionne', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'An analysis of the interrelated financial systems of central banks, private banks, and other sources and users of financial capital. Theoretical, empirical, policy and institutional issues are analyzed using economics and finance. Topics include the theory of money demand and supply, monetary policy and central banks, interest rate determination, financial intermediaries and international financial markets.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-G 345', 'MONEY, BANKING AND CAPITAL MARKETS', '3719', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'HH 3006', 'Francesco Marchionne', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'An analysis of the interrelated financial systems of central banks, private banks, and other sources and users of financial capital. Theoretical, empirical, policy and institutional issues are analyzed using economics and finance. Topics include the theory of money demand and supply, monetary policy and central banks, interest rate determination, financial intermediaries and international financial markets.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-G 345', 'MONEY, BANKING AND CAPITAL MARKETS', '12634', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'HH 3006', 'Andreas Hauskrecht', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'An analysis of the interrelated financial systems of central banks, private banks, and other sources and users of financial capital. Theoretical, empirical, policy and institutional issues are analyzed using economics and finance. Topics include the theory of money demand and supply, monetary policy and central banks, interest rate determination, financial intermediaries and international financial markets.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-G 345', 'MONEY, BANKING AND CAPITAL MARKETS', '30047', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'HH 3055', 'Andreas Hauskrecht', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'An analysis of the interrelated financial systems of central banks, private banks, and other sources and users of financial capital. Theoretical, empirical, policy and institutional issues are analyzed using economics and finance. Topics include the theory of money demand and supply, monetary policy and central banks, interest rate determination, financial intermediaries and international financial markets.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-G 350', 'BUSINESS ECONOMETRICS', '6232', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'HH 3055', 'Kerem Cakirer', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'The objective of the course is to understand various econometric, statistical, and forecasting tools for making informed business decisions. Econometric theories will be studied and applied using real-world data. Topics include linear regression, logit, probit, simultaneous equations models, two-stage least squares, time series and panel data methods.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-G 350', 'BUSINESS ECONOMETRICS', '7086', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'HH 3006', 'Tulio Salvio Dias De Sousa', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'The objective of the course is to understand various econometric, statistical, and forecasting tools for making informed business decisions. Econometric theories will be studied and applied using real-world data. Topics include linear regression, logit, probit, simultaneous equations models, two-stage least squares, time series and panel data methods.', ARRAY['Class uses IU eTexts'], NULL),
