    ('BUS-J 304', 'HONORS STRATEGIC MANAGEMENT', '11953', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'HH 4026', 'Farhan Iqbal', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course is designed to provide an appreciation for the total firm perspective and the means by which firms create and susstain competitive advantage in today''s increasingly challenging complex business environment (domestic and global). Strategic management of a firm involves diagnosing the firm''s current situation and developing realistic solutions to strategic and organizational problems which confront top managers.', ARRAY[]::TEXT[], NULL),
    ('BUS-J 306', 'STRATEGIC MANAGEMENT AND LEADERSHIP', '1151', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'WB WEB', 'Sarah Nagelvoort', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The primary objective of this course is to help develop analytical skills in identifying key strategic issues and formulating appropriate strategies given a firm''s situation. The course will provide exposure to the theories, concepts, and techniques of strategic management through the text, readings, company examples, in-class exercises, video vignettes, and guest speakers.', ARRAY[]::TEXT[], NULL),
    ('BUS-J 306', 'STRATEGIC MANAGEMENT AND LEADERSHIP', '5024', 'Closed', 'MW Monday, Wednesday 5:30 PM–6:45 PM', 'WB WEB', 'Brett Barnes', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The primary objective of this course is to help develop analytical skills in identifying key strategic issues and formulating appropriate strategies given a firm''s situation. The course will provide exposure to the theories, concepts, and techniques of strategic management through the text, readings, company examples, in-class exercises, video vignettes, and guest speakers.', ARRAY[]::TEXT[], NULL),
