    ('BUS-J 306', 'STRATEGIC MANAGEMENT AND LEADERSHIP', '29833', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'WB WEB', 'Sarah Nagelvoort', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The primary objective of this course is to help develop analytical skills in identifying key strategic issues and formulating appropriate strategies given a firm''s situation. The course will provide exposure to the theories, concepts, and techniques of strategic management through the text, readings, company examples, in-class exercises, video vignettes, and guest speakers.', ARRAY[]::TEXT[], NULL),
    ('BUS-J 375', 'STRATEGIC MANAGEMENT', '6241', 'Closed', 'Tu Tuesday 11:10 AM–12:25 PM', 'HH 2057 WB WEB', 'Lawrence Jacobson', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL), WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course is about the creation and maintenance of strong long-term organizational performance. This means that it is concerned with both the determination of strategic directions and the management of the strategic process.', ARRAY[]::TEXT[], NULL),
