    ('BUS-J 375', 'STRATEGIC MANAGEMENT', '8909', 'Closed', 'Tu Tuesday 12:45 PM–2:00 PM', 'WB WEB HH 2057', 'M.K. Chin', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL), WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course is about the creation and maintenance of strong long-term organizational performance. This means that it is concerned with both the determination of strategic directions and the management of the strategic process.', ARRAY[]::TEXT[], NULL),
    ('BUS-J 375', 'STRATEGIC MANAGEMENT', '8910', 'Closed', 'M Monday 12:45 PM–2:00 PM', 'WB WEB HH 2057', 'Sarah Nagelvoort', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL), WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course is about the creation and maintenance of strong long-term organizational performance. This means that it is concerned with both the determination of strategic directions and the management of the strategic process.', ARRAY[]::TEXT[], NULL),
    ('BUS-J 420', 'ADVANCED CASE ANALYSIS AND EFFECTIVE CONSULTING PRESENTATION', '4271', 'Closed', 'F Friday 9:00 AM–12:00 PM', 'HH 4006', 'Joel Rubin', 0, NULL, 'Practicum', '1.5', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course is dedicated to arming top students with state-of-the-art problem solving skills, intensive teamwork techniques and powerful consulting-style presentation tools. A number of frameworks will be introduced, including a focus on hypothesis-driven analysis and the pyramid principle of presentations. This course will involve several inter-class case competitions.', ARRAY[]::TEXT[], NULL),
    ('BUS-J 501', 'DEVELOPING AND IMPLEMENTING STRATEGY', '35091', 'Class Status', 'TuTh Tuesday, Thursday 1:10 PM–2:40 PM', 'CG 1022', 'Doug Eibling', 16, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course focuses on impactful components which executive management needs to consider to develop strategic capabilities and successful implementations. Through case studies and highly interactive discussions, we will examine the importance of corporate culture, transformation capabilities, intrapreneurship and leadership roles in executing various business and corporate level strategies.', ARRAY[]::TEXT[], NULL),
    ('BUS-J 540', 'STRATEGIC PLNG & MGMT PROCESS', '5876', 'Class Status', 'TuTh Tuesday, Thursday 1:00 PM–2:15 PM', 'CG 1008', 'Fred Schlegel', 4, NULL, 'Lecture', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course addresses how firms use their resources to pursue goals and adapt to the environment. Strategic planning is about setting priorities for the firm and then charting a course to achieve those priorities. Students will use skills developed in other disciplines such as accounting, marketing, finance, and IS.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-J 540', 'STRATEGIC PLNG & MGMT PROCESS', '32042', 'Class Status', 'TuTh Tuesday, Thursday 9:30 AM–10:45 AM', 'CG 1040', 'Fred Schlegel', 6, NULL, 'Lecture', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course addresses how firms use their resources to pursue goals and adapt to the environment. Strategic planning is about setting priorities for the firm and then charting a course to achieve those priorities. Students will use skills developed in other disciplines such as accounting, marketing, finance, and IS.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-J 601', 'FOUNDATIONS OF STRATEGIC MANAGEMENT', '29870', 'Class Status', 'Th Thursday 4:15 PM–9:15 PM', 'HH 3103', 'M.K. Chin', 8, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Seminal works in the field of strategic management and their impact on current research. Topics include but are not limited to environmental and industry analysis, formulation of corporate and business-level strategy, and strategy implementation. Treatment of research using archival data sources and laboratory research.', ARRAY[]::TEXT[], NULL),
    ('BUS-K 201', 'FOUNDATIONS OF BUSINESS INFORMATION SYSTEMS AND DECISION MAKING', '1152', 'Closed', 'MW Monday, Wednesday 9:10 AM–10:00 AM', 'GR 102A', 'Karen Sweeny', 0, 'Discussion', 'Discussion', '3', 'GRESHAM DINING HALL', ARRAY[]::TEXT[], 'The course provides a foundation in business information systems, decision making, and emerging technologies. Students will gain practical experience working with relational databases, spreadsheets, data visualization, and business intelligence tools essential to manage and analyze data effectively in business environments.', ARRAY['Class uses IU eTexts'], NULL),
